function tr(k){return MezanTranslations.get(T,state.settings.lang,k)}function dir(){return MezanTranslations.direction(state.settings.lang)}
function save(){try{state=MezanStorage.save(state);persistedState=JSON.parse(JSON.stringify(state));cycleCache=null;if(syncEnabled()&&!restoreSuppress)scheduleAutoSync();return true}catch{state=JSON.parse(JSON.stringify(persistedState));cycleCache=null;toast(tr('storageFull'));return false}}
function money(n){const c=state.settings.currency||wizard.currency||'QAR';return `${fmt(n)} ${currencySymbol(c,state.settings.lang)}`}
function unusuallyHigh(value){return num(value)>100000000}
function confirmUnusual(value){return !unusuallyHigh(value)||confirm(tr('unusualAmount'))}
function currencyOption(c){return `${c} — ${currencySymbol(c,state.settings.lang)}`}
function formatMoneyField(el){const raw=clean(el.value); if(!raw){el.value='';return} const parts=raw.split('.'); el.value=Number(parts[0]||0).toLocaleString('en-US')+(parts.length>1?'.'+parts.slice(1).join('').slice(0,2):'')}
function attachMoneyFormatting(){document.querySelectorAll('[data-money]').forEach(el=>el.addEventListener('input',()=>formatMoneyField(el)))}
let toastTimer;
function toast(msg,type='error'){const t=$('toast');clearTimeout(toastTimer);t.textContent=msg;t.className=`toast ${type} show`;toastTimer=setTimeout(()=>{t.classList.remove('show')},3000)}
function applyLocale(){document.documentElement.lang=state.settings.lang;document.documentElement.dir=dir();$('appName').textContent=tr('app');$('logo').textContent=tr('logo');$('tagline').textContent=tr('tag');$('arBtn').classList.toggle('active',state.settings.lang==='ar');$('enBtn').classList.toggle('active',state.settings.lang==='en');$('arBtn').setAttribute('aria-pressed',state.settings.lang==='ar');$('enBtn').setAttribute('aria-pressed',state.settings.lang==='en');document.querySelectorAll('[data-i18n]').forEach(e=>e.textContent=tr(e.dataset.i18n))}
function setLang(l){state.settings.lang=l;save();applyLocale();wizard.isEditing?renderWizard():init()}
function hasFinancialData(){return !!state.profile||state.expenses.length>0||state.salaryReceipts.length>0}
function setCurrency(c){if(hasFinancialData()&&c!==state.settings.currency){toast(tr('currencyLocked'));renderWizard();return}wizard.currency=c;if(!state.profile){state.settings.currency=c;save()}renderWizard()}
function saveDisplayName(value){state.settings.displayName=String(value||'').trim().slice(0,60);if(save())toast(tr('displayNameSaved'),'success')}
function totalIncome(){const p=state.profile||{};return num(p.salary)+num(p.extraIncome)}
function fixedCosts(){const p=state.profile||{};return num(p.rent)+num(p.internet)+num(p.electricity)+num(p.phone)+num(p.fuel)+num(p.fixed)+num(p.loans)}
function planSnapshot(){const p=state.profile||{};return {extraIncome:num(p.extraIncome),rent:num(p.rent),internet:num(p.internet),electricity:num(p.electricity),phone:num(p.phone),fuel:num(p.fuel),fixed:num(p.fixed),loans:num(p.loans),saveTarget:num(p.saveTarget)}}
function plannedSaving(){return num(state.profile?.saveTarget)}
function currentSalary(){return num(currentCycle().receipt?.amount)||num(state.profile?.salary)}
function cyclePlan(){return currentCycle().receipt?.planSnapshot||planSnapshot()}
function cycleIncome(){return currentSalary()+num(cyclePlan().extraIncome)}
function currentCycle(){return receiptCycle(state.salaryReceipts)}
function expensesInCycle(cycle){return state.expenses.filter(expense=>inCycle(expense.date,cycle))}
function cycleSnapshot(){
  if(cycleCache)return cycleCache;
  const cycle=currentCycle(),expenses=expensesInCycle(cycle),daily=expenses.filter(e=>e.kind!=='giving'&&e.kind!=='exceptional');
  const byKind={},byCategory={};
  expenses.forEach(expense=>byKind[expense.kind]=(byKind[expense.kind]||0)+num(expense.amount));
  daily.forEach(expense=>byCategory[expense.category]=(byCategory[expense.category]||0)+num(expense.amount));
  const plan=cyclePlan(),fixed=['rent','internet','electricity','phone','fuel','fixed','loans'].reduce((sum,key)=>sum+num(plan[key]),0);
  const balance=cycleBalance({salary:num(cycle.receipt?.amount)||num(state.profile?.salary),extraIncome:plan.extraIncome,fixed,saving:plan.saveTarget,expenses});
  cycleCache={cycle,expenses,daily,byKind,byCategory,balance,totalSpent:balance.spent,dailySpent:daily.reduce((sum,e)=>sum+num(e.amount),0)};
  return cycleCache;
}
function cycleExpenses(){return cycleSnapshot().expenses}
function totalCycleSpent(){return cycleSnapshot().totalSpent}
function cycleStartAvailable(){return cycleSnapshot().balance.startAvailable}
function salaryRemaining(){return cycleSnapshot().balance.remaining}
function kindTotal(kind){return cycleSnapshot().byKind[kind]||0}
function categorySpent(category){return cycleSnapshot().byCategory[category]||0}
function balanceVisual(remaining,available){
  const ratio=available>0?Math.max(0,Math.min(1,remaining/available)):0;
  const spentPct=available>0?Math.max(0,Math.round((1-ratio)*100)):0;
  const status=remaining<0?'danger':ratio<=.25?'warning':'healthy';
  const statusText=tr(status==='danger'?'balanceExceeded':status==='warning'?'balanceWatch':'balanceHealthy');
  return {ratio,spentPct,status,statusText};
}
function cycleArc(spentPct){
  const pct=Math.max(0,Math.min(100,Math.round(spentPct)));
  const r=84,cx=100,cy=110,len=Math.PI*r,progress=pct/100,theta=Math.PI*(1-progress);
  const dotX=(cx+r*Math.cos(theta)).toFixed(1),dotY=(cy-r*Math.sin(theta)).toFixed(1),offset=(len*(1-progress)).toFixed(1);
  return `<div class="cycle-arc-wrap"><svg class="cycle-arc" viewBox="0 0 200 120" role="img" aria-hidden="true"><path class="arc-track" d="M16 110 A${r} ${r} 0 0 1 184 110"></path><path class="arc-fill" d="M16 110 A${r} ${r} 0 0 1 184 110" style="stroke-dasharray:${len.toFixed(1)};stroke-dashoffset:${offset}"></path><circle class="arc-dot" cx="${dotX}" cy="${dotY}" r="7"></circle></svg><div class="cycle-arc-label"><strong>${pct}%</strong><span>${tr('spentCircle')}</span></div></div>`;
}
function balanceOrb(remaining,available){
  const visual=balanceVisual(remaining,available);
  return `<section class="balance-orb-card ${visual.status}" aria-label="${escapeHtml(tr('remainingCircle'))}: ${escapeHtml(money(remaining))}">
    ${cycleArc(visual.spentPct)}
    <div class="cycle-hero-story">
      <span class="status-tag ${visual.status}"><i aria-hidden="true">${visual.status==='healthy'?'✓':visual.status==='warning'?'!':'×'}</i>${visual.statusText}</span>
      <div class="hero-amount"><span class="hint">${tr('remainingCircle')}</span><strong class="money">${money(remaining)}</strong></div>
      <p>${tr('cycleAvailableStart')}: <b>${money(available)}</b></p>
      ${categoryBreakdown()}
      ${goalProgressRing()}
    </div>
  </section>`;
}
const DONUT_COLORS=['var(--chart-1)','var(--chart-2)','var(--chart-3)','var(--chart-4)','var(--chart-5)'];
function categoryBreakdown(){
  const entries=['food','transport','bills','fun','other'].map(category=>({category,amount:categorySpent(category)})).filter(item=>item.amount>0).sort((a,b)=>b.amount-a.amount);
  const total=entries.reduce((sum,item)=>sum+item.amount,0);
  if(!total)return `<div><div class="hint">${tr('breakdownTitle')}</div><div class="donut-empty">${tr('breakdownEmpty')}</div></div>`;
  const r=46,cx=58,cy=58,circumference=2*Math.PI*r;
  let offset=0;
  const segments=entries.map((item,i)=>{
    const len=(item.amount/total)*circumference;
    const seg=`<circle class="donut-seg" cx="${cx}" cy="${cy}" r="${r}" style="stroke:${DONUT_COLORS[i%DONUT_COLORS.length]};stroke-dasharray:${len} ${circumference-len};stroke-dashoffset:${-offset}"></circle>`;
    offset+=len;
    return seg;
  }).join('');
  const legend=entries.map((item,i)=>`<span><i style="background:${DONUT_COLORS[i%DONUT_COLORS.length]}"></i>${categoryLabel(item.category)} • ${pct(item.amount,total)}%</span>`).join('');
  return `<div><div class="hint">${tr('breakdownTitle')}</div><div class="category-donut"><svg viewBox="0 0 116 116" role="img" aria-hidden="true"><circle class="donut-bg" cx="${cx}" cy="${cy}" r="${r}"></circle>${segments}<text class="donut-total" x="${cx}" y="${cy-4}" text-anchor="middle">${fmt(total)}</text><text class="donut-label" x="${cx}" y="${cy+13}" text-anchor="middle">${tr('categoryWeights')}</text></svg><div class="donut-legend">${legend}</div></div></div>`;
}
function goalProgressRing(){
  const p=state.profile||{},saving=plannedSaving(),goalProgress=savingsProgress(p.goalAmount,state.cycleReports);
  const progressPct=Math.max(0,Math.min(100,Math.round(p.goalType==='specific'?goalProgress.progress:pct(saving,cycleIncome()))));
  const r=30,cx=36,cy=36,circumference=2*Math.PI*r,offset=circumference*(1-progressPct/100);
  return `<div><div class="hint">${tr('goalProgressLabel')}</div><div class="goal-ring"><svg viewBox="0 0 72 72" role="img" aria-hidden="true"><circle class="ring-bg" cx="${cx}" cy="${cy}" r="${r}"></circle><circle class="ring-fg" cx="${cx}" cy="${cy}" r="${r}" style="stroke-dasharray:${circumference};stroke-dashoffset:${offset}"></circle><text class="ring-pct" x="${cx}" y="${cy+5}" text-anchor="middle">${progressPct}%</text></svg><small>${tr('goalRingCaption')}</small></div></div>`;
}
function cycleHistoryBars(){
  const reports=state.cycleReports.slice(0,6).slice().reverse();
  if(!reports.length)return `<div class="card"><div class="section"><h3>${tr('historyTitle')}</h3></div><div class="empty">${tr('historyEmpty')}</div></div>`;
  const max=Math.max(...reports.map(r=>r.spent+r.saved),1);
  const cols=reports.map(r=>{
    const savedH=Math.round((r.saved/max)*64),spentH=Math.round((r.spent/max)*64);
    return `<div class="history-col" title="${escapeHtml(r.start)} - ${escapeHtml(r.end)}"><div class="history-stack"><i class="history-saved" style="height:${savedH}px"></i><i class="history-spent" style="height:${spentH}px"></i></div><small>${r.savedPct}%</small></div>`;
  }).join('');
  return `<div class="card"><div class="section"><h3>${tr('historyTitle')}</h3><span class="hint"><i class="legend-dot saved"></i>${tr('historySaved')} <i class="legend-dot spent"></i>${tr('historySpent')}</span></div><div class="history-bars">${cols}</div></div>`;
}
function dailySummaryCard(){
  const summary=dailySummary({cycle:currentCycle(),remaining:salaryRemaining(),expenses:cycleExpenses(),today:new Date()});
  const label={good:'todayGood',watch:'todayWatch',over:'todayOver'}[summary.status]||'todayGood';
  return `<div class="card today-card ${summary.status}"><div class="section"><div><span class="eyebrow">${tr('todaySummary')}</span><h3>${tr(label)}</h3></div><span class="days-badge">${summary.daysLeft}<small>${tr('daysLeft')}</small></span></div><div class="today-grid"><div><span>${tr('todayAvailable')}</span><b>${money(summary.dailyAvailable)}</b></div><div><span>${tr('spentToday')}</span><b>${money(summary.spentToday)}</b></div></div></div>`;
}
function syncRecurringPayments(){
  const cycle=currentCycle(),today=parseDate(localDate()),start=parseDate(cycle.start);
  if(!start||!today)return;
  const earliestSync=new Date(today.getFullYear(),today.getMonth()-(MAX_RECURRING_SYNC_MONTHS-1),1);
  let changed=false;
  state.recurringPayments.filter(payment=>payment.active).forEach(payment=>{
    const cursor=new Date(Math.max(new Date(start.getFullYear(),start.getMonth(),1).getTime(),earliestSync.getTime()));
    while(cursor<=today){
      const lastDay=new Date(cursor.getFullYear(),cursor.getMonth()+1,0).getDate();
      const dueDate=dateKey(new Date(cursor.getFullYear(),cursor.getMonth(),Math.min(payment.day,lastDay)));
      const monthKey=dueDate.slice(0,7);
      const exists=state.expenses.some(expense=>expense.recurringId===payment.id&&(expense.cycleKey===monthKey||expense.date===dueDate));
      if(dueDate>=cycle.start&&dueDate<=localDate()&&!exists){
        state.expenses.unshift({id:newId(),amount:payment.amount,merchant:payment.name,category:payment.category,date:dueDate,kind:'recurring',recurringId:payment.id,cycleKey:monthKey});
        changed=true;
      }
      cursor.setMonth(cursor.getMonth()+1);
    }
  });
  if(changed)save();
}
function init(){globalThis.MezanAuth?.init();ensureSyncLease();applyLocale(); if(!state.profile){$('onboarding').classList.remove('hidden');$('appArea').classList.add('hidden');$('tabs').classList.add('hidden');renderWizard()}else{syncRecurringPayments();$('onboarding').classList.add('hidden');$('appArea').classList.remove('hidden');$('tabs').classList.remove('hidden');showTab(activeTab)}}
function dots(){return `<div class="steps">${Array.from({length:7},(_,i)=>`<div class="dot ${i<=wizard.step?'on':''}"></div>`).join('')}</div>`}
function wrap(title,desc,body){const step=wizard.step+1;const stepText=state.settings.lang==='ar'?`الخطوة ${step} من 7`:`Step ${step} of 7`;return `<div class="card wizard-card"><div class="wizard-head"><div class="growth-icon" aria-hidden="true">↗</div><div><div class="eyebrow">${stepText}</div><div class="title">${title}</div><div class="desc">${desc}</div></div></div>${dots()}<div class="form">${body}</div></div>`}
function nav(back=true){return `<div class="btns">${back?`<button class="btn sec" onclick="prevStep()">${tr('back')}</button>`:wizard.isEditing?`<button class="btn sec" onclick="cancelEdit()">${tr('settings')}</button>`:''}<button class="btn ${back||wizard.isEditing?'':'full'}" onclick="nextStep()">${tr('next')}</button></div>`}
function renderWizard(){collect(); let b=''; const t=totalsFromWizard();
if(wizard.step===0)b=wrap(tr('nameTitle'),tr('nameDesc'),`<div class="field"><label for="displayName">${tr('displayName')}</label><input id="displayName" maxlength="60" placeholder="${tr('displayNamePlaceholder')}" value="${escapeHtml(wizard.displayName)}"><span class="hint">${tr('displayNameHint')}</span></div>${nav(false)}`);
if(wizard.step===1)b=wrap(tr('startTitle'),tr('startDesc'),`<div class="field"><label for="wizardCurrency">${tr('currency')}</label><select id="wizardCurrency" onchange="setCurrency(this.value)">${currencies.map(c=>`<option value="${c}" ${wizard.currency===c?'selected':''}>${currencyOption(c)}</option>`).join('')}</select></div><div class="field"><label for="salary">${tr('salary')}</label><input id="salary" data-money inputmode="decimal" value="${display(wizard.salary)}"></div><div class="field"><label for="salaryDate">${tr('salaryDate')}</label><input id="salaryDate" type="date" min="${minSalaryDate()}" max="${localDate()}" value="${wizard.salaryDate||localDate()}" ${wizard.isEditing?'disabled aria-disabled="true"':''}><span class="hint">${tr('salaryDateHint')}</span></div><div class="field"><label for="extraIncome">${tr('extra')}</label><input id="extraIncome" data-money inputmode="decimal" value="${display(wizard.extraIncome)}"></div>${nav(!wizard.isEditing)}`);
if(wizard.step===2)b=wrap(tr('housing'),tr('housingDesc'),`<div class="field"><label>${tr('rentQ')}</label><div class="choices"><button class="chip ${wizard.rentPaid==='yes'?'active':''}" aria-pressed="${wizard.rentPaid==='yes'}" onclick="setChoice('rentPaid','yes')">${tr('yes')}</button><button class="chip ${wizard.rentPaid==='no'?'active':''}" aria-pressed="${wizard.rentPaid==='no'}" onclick="setChoice('rentPaid','no')">${tr('no')}</button></div></div>${wizard.rentPaid==='yes'?`<div class="field"><label for="rent">${tr('rent')}</label><input id="rent" data-money inputmode="decimal" min="1" required value="${display(wizard.rent)}"></div>`:''}${nav()}`);
if(wizard.step===3)b=wrap(tr('bills'),tr('housingDesc'),`<div class="split"><div class="field"><label>${tr('internet')}</label><input id="internet" data-money inputmode="decimal" value="${display(wizard.internet)}"></div><div class="field"><label>${tr('electricity')}</label><input id="electricity" data-money inputmode="decimal" value="${display(wizard.electricity)}"></div></div><div class="split"><div class="field"><label>${tr('phone')}</label><input id="phone" data-money inputmode="decimal" value="${display(wizard.phone)}"></div><div class="field"><label>${tr('fuel')}</label><input id="fuel" data-money inputmode="decimal" value="${display(wizard.fuel)}"></div></div>${nav()}`);
if(wizard.step===4)b=wrap(tr('fixed'),tr('housingDesc'),`<div class="split"><div class="field"><label>${tr('payments')}</label><input id="fixed" data-money inputmode="decimal" value="${display(wizard.fixed)}"></div><div class="field"><label>${tr('loans')}</label><input id="loans" data-money inputmode="decimal" value="${display(wizard.loans)}"></div></div>${nav()}`);
if(wizard.step===5)b=wrap(tr('savingGoal'),tr('savingDesc'),`<div class="grid"><div class="metric"><div class="lab">${tr('totalIncome')}</div><div class="val good">${money(t.income)}</div></div><div class="metric"><div class="lab">${tr('fixedCosts')}</div><div class="val yellow">${money(t.fixed)}</div><span class="pct">${pct(t.fixed,t.income)}%</span></div><div class="metric wide"><div class="lab">${tr('available')}</div><div class="val blue">${money(t.available)}</div></div></div><div class="field"><label for="saveTarget">${tr('saveMonthly')} <span class="hint">${tr('max')}: ${money(t.available)}</span></label><input id="saveTarget" data-money inputmode="decimal" value="${display(wizard.saveTarget)}"></div><div class="field"><label>${tr('goalType')}</label><div class="choices"><button class="chip ${wizard.goalType==='general'?'active':''}" aria-pressed="${wizard.goalType==='general'}" onclick="setChoice('goalType','general')">${tr('general')}</button><button class="chip ${wizard.goalType==='specific'?'active':''}" aria-pressed="${wizard.goalType==='specific'}" onclick="setChoice('goalType','specific')">${tr('specific')}</button></div></div>${wizard.goalType==='specific'?`<div class="field"><label for="goalName">${tr('goalName')}</label><input id="goalName" value="${escapeHtml(wizard.goalName)}"></div><div class="split"><div class="field"><label for="goalAmount">${tr('goalAmount')}</label><input id="goalAmount" data-money inputmode="decimal" value="${display(wizard.goalAmount)}"></div><div class="field"><label for="goalMonths">${tr('goalMonths')}</label><input id="goalMonths" type="number" min="1" inputmode="numeric" value="${display(wizard.goalMonths)}"></div></div>`:''}${nav()}`);
if(wizard.step===6)b=wrap(tr('review'),tr('reviewDesc'),`<div class="grid"><div class="metric"><div class="lab">${tr('income')}</div><div class="val good">${money(t.income)}</div></div><div class="metric"><div class="lab">${tr('fixedCosts')}</div><div class="val yellow">${money(t.fixed)}</div><span class="pct">${pct(t.fixed,t.income)}%</span></div><div class="metric"><div class="lab">${tr('saving')}</div><div class="val blue">${money(t.saving)}</div><span class="pct">${pct(t.saving,t.income)}%</span></div><div class="metric"><div class="lab">${tr('cycleAvailableStart')}</div><div class="val ${t.free>=0?'good':'bad'}">${money(Math.max(0,t.free))}</div><span class="pct">${pct(Math.max(0,t.free),t.income)}%</span></div></div><div class="notice">${tr('fixedPct')} <b>${pct(t.fixed,t.income)}%</b> ${tr('ofIncome')}. ${tr('savingPct')} <b>${pct(t.saving,t.income)}%</b>. ${tr('freePct')} <b>${pct(Math.max(0,t.free),t.income)}%</b>.</div><p class="copy ${t.free<0?'bad':'good'}">${t.free<0?tr('adviceBad'):tr('adviceOk')}</p><div class="btns"><button class="btn sec" onclick="prevStep()">${tr('back')}</button><button class="btn" onclick="finishWizard()" ${t.free<0?'disabled aria-disabled="true"':''}>${tr('approve')}</button></div>`);
$('onboarding').innerHTML=b;$('onboarding').onkeydown=event=>{if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();wizard.step===6?finishWizard():nextStep()}};attachMoneyFormatting();}
function collect(){['displayName','salary','salaryDate','extraIncome','rent','internet','electricity','phone','fuel','fixed','loans','saveTarget','goalName','goalAmount','goalMonths'].forEach(id=>{const el=$(id);if(el)wizard[id]=el.value}); if(wizard.rentPaid==='no')wizard.rent=''}
function hasValidRent(){return wizard.rentPaid!=='yes'||num(wizard.rent)>0}
function validFirstSalaryDate(){return !!parseDate(wizard.salaryDate)&&wizard.salaryDate>=minSalaryDate()&&wizard.salaryDate<=localDate()}
function validSpecificGoal(){return wizard.goalType!=='specific'||(wizard.goalName.trim()&&num(wizard.goalAmount)>0&&num(wizard.goalMonths)>0)}
function setChoice(k,v){collect();wizard[k]=v;renderWizard()}function nextStep(){collect();const t=totalsFromWizard();if(wizard.step===1&&num(wizard.salary)<=0){toast(tr('toastSalary'));return}if(wizard.step===1&&!confirmUnusual(wizard.salary)){return}if(wizard.step===1&&!wizard.isEditing&&!validFirstSalaryDate()){toast(tr('toastFirstDate'));return}if(wizard.step===2&&!hasValidRent()){toast(tr('toastRent'));$('rent')?.focus();return}if(wizard.step===5&&num(wizard.saveTarget)>t.available){toast(tr('toastSave'));return}if(wizard.step===5&&!validSpecificGoal()){toast(tr('toastGoalDetails'));return}wizard.step=Math.min(6,wizard.step+1);renderWizard()}function prevStep(){collect();wizard.step=Math.max(wizard.isEditing?1:0,wizard.step-1);renderWizard()}
function finishWizard(){collect();const totals=totalsFromWizard();if(num(wizard.salary)<=0){wizard.step=1;renderWizard();toast(tr('toastSalary'));return}if(!wizard.isEditing&&!validFirstSalaryDate()){wizard.step=1;renderWizard();toast(tr('toastFirstDate'));return}if(!hasValidRent()){wizard.step=2;renderWizard();toast(tr('toastRent'));$('rent')?.focus();return}if(!validSpecificGoal()){wizard.step=5;renderWizard();toast(tr('toastGoalDetails'));return}if(totals.free<0){toast(tr('adviceBad'));return}const wasEditing=wizard.isEditing;state.settings.currency=wizard.currency;state.settings.displayName=wizard.displayName.trim().slice(0,60);const previousDate=state.profile?.salaryDate;state.profile={salary:num(wizard.salary),salaryDate:wasEditing?previousDate:(wizard.salaryDate||localDate()),extraIncome:num(wizard.extraIncome),rentPaid:wizard.rentPaid,rent:num(wizard.rent),internet:num(wizard.internet),electricity:num(wizard.electricity),phone:num(wizard.phone),fuel:num(wizard.fuel),fixed:num(wizard.fixed),loans:num(wizard.loans),saveTarget:num(wizard.saveTarget),goalType:wizard.goalType,goalName:wizard.goalName||tr('generalSave'),goalAmount:num(wizard.goalAmount),goalMonths:num(wizard.goalMonths)};if(!state.salaryReceipts.length)state.salaryReceipts.push({id:newId(),date:state.profile.salaryDate,amount:state.profile.salary,planSnapshot:planSnapshot()});else if(wasEditing)state.salaryReceipts[state.salaryReceipts.length-1].planSnapshot=planSnapshot();wizard.isEditing=false;if(!save())return;init();toast(tr('toastDone'),'success')}
function restartWizard(){const p=state.profile||{};wizard={step:1,isEditing:true,currency:state.settings.currency||'QAR',displayName:state.settings.displayName||'',salary:p.salary||'',salaryDate:p.salaryDate||localDate(),extraIncome:p.extraIncome||'',rentPaid:p.rentPaid||'no',rent:p.rent||'',internet:p.internet||'',electricity:p.electricity||'',phone:p.phone||'',fuel:p.fuel||'',fixed:p.fixed||'',loans:p.loans||'',saveTarget:p.saveTarget||'',goalType:p.goalType||'general',goalName:p.goalName||'',goalAmount:p.goalAmount||'',goalMonths:p.goalMonths||''};$('onboarding').classList.remove('hidden');$('appArea').classList.add('hidden');$('tabs').classList.add('hidden');renderWizard()}
function cancelEdit(){wizard.isEditing=false;init();showTab('settings')}
function renderTab(id){({dashboard:renderDashboard,expense:renderExpense,budget:renderBudget,chat:renderChat,settings:renderSettings}[id]||renderDashboard)()}
function renderAll(){renderTab(activeTab)}
function goalScheduleText(profile,saving){
  if(profile.goalType!=='specific'||!profile.goalAmount)return'';
  const progress=savingsProgress(profile.goalAmount,state.cycleReports);
  const progressText=`${tr('goalSavedSoFar')}: <b class="good">${money(progress.saved)}</b> • ${tr('goalRemaining')}: <b>${money(progress.remaining)}</b>.`;
  if(!saving)return`${progressText} ${tr('savingZero')}`;
  const estimated=Math.ceil(progress.remaining/saving);
  if(!profile.goalMonths)return`${progressText} ${tr('needMonths')} <b>${estimated}</b> ${tr('months')}.`;
  const required=progress.remaining/profile.goalMonths;
  return state.settings.lang==='ar'
    ?`${progressText} للوصول خلال <b>${fmt(profile.goalMonths)}</b> شهر تحتاج <b>${money(required)}</b> شهرياً. بخطتك الحالية تحتاج تقريباً <b>${estimated}</b> شهر.`
    :`${progressText} To reach it in <b>${fmt(profile.goalMonths)}</b> months, save <b>${money(required)}</b> monthly. Your current plan takes about <b>${estimated}</b> months.`;
}
function reportLabel(key){const allowed={rent:'rent',internet:'internet',electricity:'electricity',phone:'phone',fuel:'fuel',fixed:'payments',loans:'loans',food:'food',transport:'transport',bills:'billsCat',fun:'fun',other:'other',exceptional:'exceptionalTotal',giving:'giving'};return tr(allowed[key]||'other')}
function buildCycleReport(cycle,receipt){
  const expenses=expensesInCycle(cycle);
  const plan=receipt.planSnapshot||planSnapshot();
  const breakdown=new Map();
  const add=(key,amount)=>{amount=num(amount);if(amount)breakdown.set(key,(breakdown.get(key)||0)+amount)};
  ['rent','internet','electricity','phone','fuel','fixed','loans'].forEach(key=>add(key,plan[key]));
  expenses.forEach(expense=>{
    if(expense.kind==='giving')add('giving',expense.amount);
    else if(expense.kind==='exceptional')add('exceptional',expense.amount);
    else add(expense.category,expense.amount);
  });
  const items=[...breakdown.entries()].map(([key,amount])=>({key,amount})).sort((a,b)=>b.amount-a.amount);
  const totals=completedCycleReport({salary:receipt.amount,plan,expenses}),salary=num(receipt.amount);
  return {id:newId(),start:cycle.start,end:cycle.end,days:cycleProgress(cycle,parseDate(cycle.end)).total,salary,spent:totals.spent,saved:totals.saved,savedPct:pct(totals.saved,totals.income),topKey:items[0]?.key||'other',topAmount:items[0]?.amount||0,breakdown:items,expenses:expenses.map(expense=>({...expense}))};
}
function expenseKindClass(kind){return ['regular','recurring','exceptional','giving'].includes(kind)?kind:'regular'}
function reportExpenseList(report){
  if(!report.expenses.length)return `<div class="empty">${tr('reportEmpty')}</div>`;
  return `<div class="list">${report.expenses.map(expense=>`<div class="rowline expense-row ${expenseKindClass(expense.kind)}"><div><b>${escapeHtml(expense.merchant||tr('expense'))}</b><small>${escapeHtml(expense.date)} • ${escapeHtml(expenseKindLabel(expense))}</small></div><div class="money">${money(expense.amount)}</div></div>`).join('')}</div>`;
}
function reportSummaryText(report){
  return state.settings.lang==='ar'
    ?`تهانينا! لقد أتممت <b>${report.days}</b> يوماً منذ آخر راتب قبضته. استطعت توفير <b class="good">${money(report.saved)}</b>، أي <b>${report.savedPct}%</b> من الراتب المستلم.`
    :`Congratulations! You completed <b>${report.days}</b> days since your last salary. You saved <b class="good">${money(report.saved)}</b>, or <b>${report.savedPct}%</b> of the salary received.`;
}
function reportCard(report,latest=false){
  if(!report)return'';
  return `<div class="card cycle-report ${latest?'latest-report':''}"><div class="section"><div><span class="eyebrow">${tr('cycleComplete')}</span><h3><bdi dir="ltr">${escapeHtml(report.start)} - ${escapeHtml(report.end)}</bdi></h3></div><span class="report-score">${report.savedPct}%</span></div><p class="report-message">${reportSummaryText(report)}</p><div class="report-grid"><div class="metric"><div class="lab">${tr('totalSpent')}</div><div class="val yellow">${money(report.spent)}</div></div><div class="metric"><div class="lab">${tr('topSpending')}</div><div class="val blue">${reportLabel(report.topKey)}</div><span class="pct">${money(report.topAmount)}</span></div></div><div class="breakdown-list">${report.breakdown.map(item=>`<div><span>${reportLabel(item.key)}</span><b>${money(item.amount)}</b></div>`).join('')}</div><p class="copy">${tr('nextCycleWish')}</p><details><summary>${tr('fullReport')}</summary><div class="report-expenses"><h4>${tr('actualExpenses')}</h4>${reportExpenseList(report)}</div></details></div>`;
}
function registerSalary(){
  const date=$('receivedSalaryDate').value,amount=num($('receivedSalaryAmount').value),latest=state.salaryReceipts[state.salaryReceipts.length-1];
  if(!amount){toast(tr('toastSalary'));return}
  if(!confirmUnusual(amount))return;
  if(date>localDate()){toast(tr('salaryDateFuture'));return}
  if(!parseDate(date)){toast(tr('toastFirstDate'));return}
  if(!latest){
    state.salaryReceipts.push({id:newId(),date,amount,planSnapshot:planSnapshot()});
    state.profile.salaryDate=date;
    if(!save())return;
    syncRecurringPayments();
    showTab('dashboard');
    toast(tr('firstSalaryRegistered'),'success');
    return;
  }
  if(date<=latest.date){toast(tr('salaryDateOld'));return}
  const cycle=closedReceiptCycle(latest.date,date);
  if(!cycle){toast(tr('salaryDateOld'));return}
  state.cycleReports.unshift(buildCycleReport(cycle,latest));
  state.salaryReceipts.push({id:newId(),date,amount,planSnapshot:planSnapshot()});
  state.profile.salaryDate=date;
  if(!save())return;
  syncRecurringPayments();
  showTab('dashboard');
  toast(tr('salaryRegistered'),'success');
}
function renderDashboard(){
  const income=cycleIncome(),fixed=fixedCosts(),saving=plannedSaving(),spent=totalCycleSpent();
  const available=cycleStartAvailable(),remaining=salaryRemaining(),cycle=currentCycle();
  const elapsed=cycleProgress(cycle).elapsed;
  const giving=kindTotal('giving'),exceptional=kindTotal('exceptional'),p=state.profile,goalProgress=savingsProgress(p.goalAmount,state.cycleReports);
  $('dashboard').innerHTML=`<div class="card glass hero"><div class="section"><div>${state.settings.displayName?`<span class="eyebrow">${tr('greeting')(escapeHtml(state.settings.displayName))}</span>`:''}<h2>${tr('dashTitle')}</h2><p>${tr('dashDesc')}</p></div><span class="cycle-pill">${tr('openCycle')}: <bdi dir="ltr">${cycle.start}</bdi> • ${tr('untilNextSalary')}</span></div><div class="btns"><button class="btn" onclick="showTab('expense')">${tr('addExpense')}</button><button class="btn sec" onclick="showTab('budget')">${tr('viewPlan')}</button></div></div>${dailySummaryCard()}${backupDue()?`<div class="card backup-card"><p class="copy">${tr('backupReminder')}</p><button class="btn" onclick="exportData()">${tr('backupNow')}</button></div>`:''}${balanceOrb(remaining,available)}<div class="card salary-receipt-card"><div class="section"><div><h3>${tr('receivedSalary')}</h3><p class="copy">${tr('receivedSalaryDesc')}</p></div><span class="days-badge">${elapsed}<small>${tr('daysSinceSalary')}</small></span></div><div class="split"><div class="field"><label for="receivedSalaryDate">${tr('newSalaryDate')}</label><input id="receivedSalaryDate" type="date" max="${localDate()}" value="${localDate()}"></div><div class="field"><label for="receivedSalaryAmount">${tr('salaryAmount')}</label><input id="receivedSalaryAmount" data-money inputmode="decimal" value="${display(currentSalary())}"></div></div><button class="btn" onclick="registerSalary()">${tr('registerSalary')}</button></div>${state.cycleReports.length?reportCard(state.cycleReports[0],true):''}${state.cycleReports.length>1?cycleHistoryBars():''}<div class="grid cycle-metrics"><div class="metric"><div class="lab">${tr('cycleSalary')}</div><div class="val good">${money(currentSalary())}</div></div><div class="metric"><div class="lab">${tr('cycleSpending')}</div><div class="val ${spent>available?'bad':'yellow'}">${money(spent)}</div><span class="pct">${pct(spent,income)}%</span></div>${giving?`<div class="metric"><div class="lab">${tr('giving')}</div><div class="val good">${money(giving)}</div></div>`:''}${exceptional?`<div class="metric"><div class="lab">${tr('exceptionalTotal')}</div><div class="val yellow">${money(exceptional)}</div></div>`:''}</div><div class="card"><div class="section"><h3>${tr('goal')}</h3><span class="hint">${escapeHtml(p.goalName||tr('generalSave'))}</span></div><p class="copy">${tr('plannedToSave')} <b class="good">${money(saving)}</b> ${tr('monthly')}. ${goalScheduleText(p,saving)}</p><div class="barwrap"><div class="bar" style="width:${p.goalType==='specific'?goalProgress.progress:Math.min(100,pct(saving,income))}%"></div></div></div><div class="card"><div class="section"><h3>${tr('lastExpenses')}</h3><span class="hint"><bdi dir="ltr">${cycle.start}</bdi> • ${tr('openCycle')}</span></div>${expenseList(5)}</div>`;
  attachMoneyFormatting();
}
function categoryLabel(category){return tr({food:'food',transport:'transport',bills:'billsCat',fun:'fun',other:'other'}[category]||'other')}
function categoryOptions(selected='auto',includeAuto=true){const options=[['food','food'],['transport','transport'],['bills','billsCat'],['fun','fun'],['other','other']];return `${includeAuto?`<option value="auto" ${selected==='auto'?'selected':''}>${tr('auto')}</option>`:''}${options.map(([value,key])=>`<option value="${value}" ${selected===value?'selected':''}>${tr(key)}</option>`).join('')}`}
function renderExpense(){
  const editing=state.expenses.find(expense=>expense.id===editingExpenseId);
  const cycle=currentCycle();
  $('expense').innerHTML=`<div class="card"><div class="section"><h3>${editing?tr('editExpense'):tr('addExpense')}</h3><span class="hint">${tr('auto')}</span></div><div class="form"><div class="field"><label for="exAmount">${tr('amount')}</label><input id="exAmount" data-money inputmode="decimal" value="${display(editing?.amount)}"></div><div class="field"><label for="exMerchant">${tr('merchant')}</label><input id="exMerchant" maxlength="100" value="${escapeHtml(editing?.merchant||'')}"></div><div class="split"><div class="field"><label for="exDate">${tr('date')}</label><input id="exDate" type="date" min="${cycle.start}" max="${localDate()}" value="${editing?.date||localDate()}"></div><div class="field"><label for="exCategory">${tr('category')}</label><select id="exCategory">${categoryOptions(editing?.category||'auto')}</select></div></div><div class="btns"><button class="btn" onclick="saveExpense()">${editing?tr('updateExpense'):tr('saveExpense')}</button>${editing?`<button class="btn sec" onclick="cancelExpenseEdit()">${tr('cancel')}</button>`:''}</div></div></div><div class="card giving-card"><div class="section"><div><h3>${tr('specialGiving')}</h3><p class="copy">${tr('specialGivingHint')}</p></div><span class="section-icon">+</span></div><div class="form"><div class="split"><div class="field"><label for="specialType">${tr('paymentType')}</label><select id="specialType"><option value="parents">${tr('parents')}</option><option value="family">${tr('family')}</option><option value="charity">${tr('charity')}</option><option value="gift">${tr('gift')}</option><option value="emergency">${tr('emergency')}</option><option value="exceptional">${tr('exceptional')}</option></select></div><div class="field"><label for="specialAmount">${tr('amount')}</label><input id="specialAmount" data-money inputmode="decimal"></div></div><div class="split"><div class="field"><label for="specialDescription">${tr('merchant')}</label><input id="specialDescription" maxlength="100"></div><div class="field"><label for="specialDate">${tr('date')}</label><input id="specialDate" type="date" min="${cycle.start}" max="${localDate()}" value="${localDate()}"></div></div><button class="btn giving-btn" onclick="addSpecialPayment()">${tr('savePayment')}</button></div></div><div class="card"><div class="section"><h3>${tr('allExpenses')}</h3><span class="hint">${tr('newest')}</span></div>${expenseList(50)}</div>`;
  attachMoneyFormatting();
}
function rememberMerchantCategory(merchant,category){const key=merchant.trim().toLowerCase();if(key&&!BLOCKED_MERCHANT_KEYS.has(key)&&category!=='auto')state.merchantCategories[key]=category}
function validExpenseDate(date){return !!parseDate(date)&&inCycle(date,currentCycle())}
function budgetAlert(category,spent,limit){if(!limit)return'';const level=spent>=limit?'100':spent>=limit*.8?'80':'';if(!level)return'';const key=`${currentCycle().start}:${category}:${level}`;if(state.budgetAlerts[key])return'';state.budgetAlerts[key]=true;return level==='100'?tr('budgetOver'):tr('budgetNear')}
function saveExpense(){const amount=num($('exAmount').value),merchant=$('exMerchant').value.trim(),date=$('exDate').value,chosen=$('exCategory').value;if(!amount){toast(tr('toastAmount'));return}if(!validExpenseDate(date)){toast(tr('toastDate'));return}const category=chosen==='auto'?classifyMerchant(merchant,state.merchantCategories):chosen;rememberMerchantCategory(merchant,category);const existing=state.expenses.find(expense=>expense.id===editingExpenseId);if(existing){Object.assign(existing,{amount,merchant,category,date});editingExpenseId=null}else state.expenses.unshift({id:newId(),amount,merchant,category,date,kind:'regular'});const limit=num(state.categoryBudgets[category]);cycleCache=null;const spent=categorySpent(category),alert=existing?'':budgetAlert(category,spent,limit);if(!save())return;showTab('dashboard');if(existing)toast(tr('expenseUpdated'),'success');else if(alert)toast(`${alert}: ${categoryLabel(category)}`);else toast(tr('toastExpense'),'success')}
function addExpense(){saveExpense()}
function editExpense(id){editingExpenseId=id;showTab('expense')}
function cancelExpenseEdit(){editingExpenseId=null;renderExpense()}
function addSpecialPayment(){const amount=num($('specialAmount').value),subtype=$('specialType').value,date=$('specialDate').value,description=$('specialDescription').value.trim();if(!amount){toast(tr('toastAmount'));return}if(!validExpenseDate(date)){toast(tr('toastDate'));return}const givingTypes=new Set(['parents','family','charity','gift']),kind=givingTypes.has(subtype)?'giving':'exceptional';state.expenses.unshift({id:newId(),amount,merchant:description,category:'other',date,kind,subtype});if(!save())return;showTab('dashboard');toast(tr('specialSaved'),'success')}
function expenseKindLabel(expense){const subtypes=new Set(['parents','family','charity','gift','emergency','exceptional']);if(expense.kind==='giving')return tr(subtypes.has(expense.subtype)?expense.subtype:'giving');if(expense.kind==='exceptional')return tr(subtypes.has(expense.subtype)?expense.subtype:'exceptional');if(expense.kind==='recurring')return tr('recurringExpense');return categoryLabel(expense.category)}
function expenseList(limit){const arr=cycleExpenses().slice(0,limit);if(!arr.length)return `<div class="empty">${tr('noExpenses')}</div>`;return `<div class="list">${arr.map(e=>`<div class="rowline expense-row ${expenseKindClass(e.kind)}"><div><b>${escapeHtml(e.merchant||tr('expense'))}</b><small>${escapeHtml(e.date)} • ${escapeHtml(expenseKindLabel(e))}</small></div><div class="amount-actions"><div class="money">${money(e.amount)}</div><div class="expense-actions"><button class="chip mini" onclick="editExpense(${Number(e.id)})">${tr('edit')}</button><button class="chip mini" onclick="deleteExpense(${Number(e.id)})">${tr('delete')}</button></div></div></div>`).join('')}</div>`}
function deleteExpense(id){if(!confirm(tr('deleteExpenseConfirm')))return;state.expenses=state.expenses.filter(e=>e.id!==id);if(editingExpenseId===id)editingExpenseId=null;save();renderAll()}
function categoryBudgetRows(){return ['food','transport','bills','fun','other'].map(category=>{const limit=num(state.categoryBudgets[category]),spent=categorySpent(category),progress=limit?pct(spent,limit):0,status=progress>=100?'danger':progress>=80?'warning':'';return `<div class="budget-category"><div class="section"><b>${categoryLabel(category)}</b><span class="money">${limit?`${money(spent)} / ${money(limit)}`:`${money(spent)} • ${tr('noLimit')}`}</span></div>${limit?`<div class="barwrap" aria-label="${progress}%"><div class="bar ${status==='danger'?'danger-bar':status==='warning'?'warn':''}" style="width:${Math.min(100,progress)}%"></div></div>${status?`<span class="status-tag ${status} mini"><i aria-hidden="true">${status==='danger'?'×':'!'}</i>${tr(status==='danger'?'budgetOver':'budgetNear')}</span>`:''}`:''}</div>`}).join('')}
function recurringList(){if(!state.recurringPayments.length)return `<div class="empty">${tr('noRecurring')}</div>`;return `<div class="list">${state.recurringPayments.map(payment=>`<div class="rowline"><div><b>${escapeHtml(payment.name)}</b><small>${categoryLabel(payment.category)} • ${tr('paymentDay')} ${payment.day}</small></div><div class="amount-actions"><div class="money">${money(payment.amount)}</div><button class="chip mini" onclick="deleteRecurring(${Number(payment.id)})">${tr('delete')}</button></div></div>`).join('')}</div>`}
function renderBudget(){
  const income=cycleIncome(),fixed=fixedCosts(),saving=plannedSaving(),variable=cycleStartAvailable(),spent=totalCycleSpent();
  const items=[[tr('rent'),state.profile.rent],[tr('internet'),state.profile.internet],[tr('electricity'),state.profile.electricity],[tr('phone'),state.profile.phone],[tr('fuel'),state.profile.fuel],[tr('payments'),state.profile.fixed],[tr('loans'),state.profile.loans],[tr('saving'),saving],[tr('remainSpend'),variable]];
  $('budget').innerHTML=`<div class="card"><div class="section"><h3>${tr('budgetTitle')}</h3><span class="hint">${money(income)}</span></div>${items.filter(item=>num(item[1])>0).map(([name,value])=>{const percentage=pct(value,income);return `<div class="rowline block"><div class="section"><b>${name}</b><span class="money">${money(value)} • ${percentage}%</span></div><div class="barwrap"><div class="bar ${percentage>45?'warn':''}" style="width:${Math.min(100,percentage)}%"></div></div></div>`}).join('')}<p class="copy">${tr('totalCycleSpending')}: <b>${money(spent)}</b> ${tr('from')} <b>${money(variable)}</b>.</p></div><div class="card"><div class="section"><div><h3>${tr('categoryBudgets')}</h3><p class="copy">${tr('categoryBudgetHint')}</p></div></div><div class="category-budget-grid">${['food','transport','bills','fun','other'].map(category=>`<div class="field"><label for="budget-${category}">${categoryLabel(category)}</label><input id="budget-${category}" data-money inputmode="decimal" value="${display(state.categoryBudgets[category])}"></div>`).join('')}</div><button class="btn" onclick="saveCategoryBudgets()">${tr('saveBudgets')}</button><div class="budget-progress">${categoryBudgetRows()}</div></div><div class="card"><div class="section"><div><h3>${tr('recurring')}</h3><p class="copy">${tr('recurringHint')} ${tr('duplicateCommitmentHint')}</p></div></div><div class="form"><div class="field"><label for="recurringName">${tr('paymentName')}</label><input id="recurringName" maxlength="80"></div><div class="split"><div class="field"><label for="recurringAmount">${tr('amount')}</label><input id="recurringAmount" data-money inputmode="decimal"></div><div class="field"><label for="recurringDay">${tr('paymentDay')}</label><input id="recurringDay" type="number" min="1" max="31" inputmode="numeric" value="${currentCycle().salaryDay}"></div></div><div class="field"><label for="recurringCategory">${tr('category')}</label><select id="recurringCategory">${categoryOptions('bills',false)}</select></div><button class="btn sec" onclick="addRecurringPayment()">${tr('addRecurring')}</button></div>${recurringList()}</div>`;
  attachMoneyFormatting();
}
function saveCategoryBudgets(){['food','transport','bills','fun','other'].forEach(category=>state.categoryBudgets[category]=num($(`budget-${category}`).value));if(!save())return;renderBudget();toast(tr('budgetsSaved'),'success')}
function addRecurringPayment(){const name=$('recurringName').value.trim(),amount=num($('recurringAmount').value),day=Math.min(31,Math.max(1,num($('recurringDay').value)||1)),category=$('recurringCategory').value;if(!name||!amount){toast(tr('toastAmount'));return}state.recurringPayments.push({id:newId(),name,amount,day,category,active:true});if(!save())return;syncRecurringPayments();showTab('budget');toast(tr('recurringSaved'),'success')}
function deleteRecurring(id){if(!confirm(tr('deleteRecurringConfirm')))return;state.recurringPayments=state.recurringPayments.filter(payment=>payment.id!==id);state.expenses.forEach(expense=>{if(expense.recurringId===id)expense.recurringId=null});if(!save())return;showTab('budget')}
function buildFinancialContext(){
  const cycle=currentCycle(),p=state.profile||{},isArabic=state.settings.lang==='ar';
  const topCategories=['food','transport','bills','fun','other'].map(category=>({category,spent:categorySpent(category)})).filter(item=>item.spent>0).sort((a,b)=>b.spent-a.spent).slice(0,3).map(item=>`${categoryLabel(item.category)} ${money(item.spent)}`).join(', ')||tr('noExpenses');
  const recent=cycleExpenses().slice(0,8).map(expense=>`${expense.date}: ${expense.merchant||categoryLabel(expense.category)} ${money(expense.amount)}`).join('; ')||tr('noExpenses');
  const labels=isArabic?{language:'\u0627\u0644\u0644\u063a\u0629',currency:'\u0627\u0644\u0639\u0645\u0644\u0629',cycle:'\u062f\u0648\u0631\u0629 \u0627\u0644\u0631\u0627\u062a\u0628',income:'\u0627\u0644\u062f\u062e\u0644 \u0627\u0644\u0634\u0647\u0631\u064a',fixed:'\u0627\u0644\u0645\u0635\u0627\u0631\u064a\u0641 \u0627\u0644\u062b\u0627\u0628\u062a\u0629',savings:'\u0647\u062f\u0641 \u0627\u0644\u0627\u062f\u062e\u0627\u0631',available:'\u0627\u0644\u0645\u062a\u0628\u0642\u064a \u0644\u0644\u0625\u0646\u0641\u0627\u0642',spent:'\u0625\u062c\u0645\u0627\u0644\u064a \u0625\u0646\u0641\u0627\u0642 \u0627\u0644\u062f\u0648\u0631\u0629',top:'\u0623\u0639\u0644\u0649 \u0627\u0644\u0641\u0626\u0627\u062a',recent:'\u0622\u062e\u0631 \u0627\u0644\u0645\u0635\u0631\u0648\u0641\u0627\u062a'}:{language:'Language',currency:'Currency',cycle:'Pay cycle',income:'Monthly income',fixed:'Fixed costs',savings:'Savings target',available:'Remaining to spend',spent:'Spent this cycle',top:'Top categories',recent:'Recent expenses'};
  return [`${labels.language}: ${state.settings.lang}`,`${labels.currency}: ${state.settings.currency}`,`${labels.cycle}: ${cycle.start} to ${cycle.end||localDate()}`,`${labels.income}: ${money(cycleIncome())}`,`${labels.fixed}: ${money(fixedCosts())}`,`${labels.savings}: ${p.goalName||tr('generalSave')} (${money(p.goalAmount||0)}); ${money(plannedSaving())} ${tr('monthly')}`,`${labels.available}: ${money(salaryRemaining())}`,`${labels.spent}: ${money(totalCycleSpent())}`,`${labels.top}: ${topCategories}`,`${labels.recent}: ${recent}`].join('\n').slice(0,MAX_FINANCIAL_CONTEXT_LENGTH);
}
function chatMessageRow(message){return `<div class="chat-msg ${message.role}"><b>${message.role==='user'?tr('chat'):tr('chatTitle')}</b><p>${escapeHtml(message.text)}</p></div>`}
function chatSamples(){return state.settings.lang==='ar'?['كم باقي من راتبي؟','كم صرفت على الطعام هذا الشهر؟','هل أنا داخل حدود ميزانيتي؟']:['How much salary is left?','How much did I spend on food this month?','Am I within my budget?']}
function askSample(text){const input=$('chatQuestion');if(!input||input.disabled)return;input.value=text;sendChatMessage()}
function chatMessagesHtml(){
  if(chatMessages.length)return chatMessages.map(chatMessageRow).join('');
  const chips=chatSamples().map(q=>`<button class="chat-sample" onclick="askSample('${q}')">${escapeHtml(q)}</button>`).join('');
  return `<div class="chat-empty"><p>${tr('chatEmpty')}</p><div class="chat-samples">${chips}</div></div>`;
}
function renderChat(){
  const configured=!!CHAT_API_URL&&/\/chat$/.test(CHAT_API_URL),auth=globalThis.MezanAuth;
  const profile=auth?.getProfile(),displayName=profile?.name||profile?.email,signedIn=!!auth?.isSignedIn();
  const authState=signedIn?`${displayName?`<p class="hint">${tr('signedInAs')} ${escapeHtml(displayName)}</p>`:''}<div class="chat-thread" id="chatThread" aria-live="polite">${chatMessagesHtml()}${chatLoading?`<div class="chat-msg bot"><b>${tr('chatTitle')}</b><p>${tr('chatThinking')}</p></div>`:''}</div><div class="chat-input-row"><input id="chatQuestion" maxlength="300" placeholder="${tr('chatPlaceholder')}" ${chatLoading||!configured?'disabled':''}><button class="btn" onclick="sendChatMessage()" ${chatLoading||!configured?'disabled':''}>${tr('chatSend')}</button></div>`:`<div class="notice"><p>${chatAuthMessage||tr('chatSignInPrompt')}</p><div id="googleSignInBtn" class="gsi-container"></div></div>`;
  $('chat').innerHTML=`<div class="card chat-card"><div class="section"><div><h3>${tr('chatTitle')}</h3><p class="copy">${tr('chatDesc')}</p></div><span class="section-icon">✦</span></div><p class="chat-privacy">${tr('chatPrivacyNote')}</p>${configured?'':`<div class="notice">${tr('chatNotConfigured')}</div>`}${authState}</div>`;
  if(!signedIn)requestAnimationFrame(()=>auth?.renderButton?.($('googleSignInBtn')));
}
async function sendChatMessage(){
  const input=$('chatQuestion'),question=input?.value.trim(),idToken=globalThis.MezanAuth?.getIdToken();
  if(!question||!idToken)return;
  const history=chatMessages.slice(-MAX_CHAT_HISTORY_MESSAGES).map(message=>({role:message.role==='user'?'user':'assistant',text:message.text}));
  chatMessages.push({role:'user',text:question});
  chatLoading=true;renderChat();
  try{
    const response=await fetch(CHAT_API_URL,{method:'POST',headers:{'Content-Type':'application/json','Authorization':`Bearer ${idToken}`},body:JSON.stringify({lang:state.settings.lang,question,history,financialContext:buildFinancialContext()})});
    if(response.status===401){chatAuthMessage=tr('chatSessionExpired');MezanAuth.signOut();return}
    const data=await response.json().catch(()=>({}));
    chatMessages.push({role:'bot',text:data.answer||data.message||tr(response.status===429?'chatLimitReached':'chatError')});
  }catch{
    chatMessages.push({role:'bot',text:tr('chatError')});
  }finally{
    chatLoading=false;renderChat();
  }
}
MezanAuth.onChange(()=>{if(MezanAuth.isSignedIn())chatAuthMessage='';ensureSyncLease();if(activeTab==='chat')renderChat();if(activeTab==='settings')renderSettings()});
function backupDue(){
  if(!state.expenses.length)return false;
  const today=parseDate(localDate()),last=parseDate(state.settings.lastBackupAt);
  if(!today)return false;
  if(last)return Math.floor((today-last)/86400000)>=30;
  const first=state.expenses.map(expense=>parseDate(expense.date)).filter(Boolean).sort((a,b)=>a-b)[0];
  const daysSinceFirst=first?Math.floor((today-first)/86400000):0;
  return state.expenses.length>=10||daysSinceFirst>=7;
}
function syncMeta(){try{return JSON.parse(localStorage.getItem('mezan_sync_meta'))||{}}catch{return {}}}
function saveSyncMeta(meta){localStorage.setItem('mezan_sync_meta',JSON.stringify(meta))}
function deviceId(){let id=localStorage.getItem('mezan_device_id');if(!id){id=globalThis.crypto?.randomUUID?.()||`mezan-${Date.now()}-${Math.random().toString(36).slice(2)}`;localStorage.setItem('mezan_device_id',id)}return id}
let syncLeaseStatus='off',syncLeaseHeartbeat=null,syncLeaseBusy=false,syncConflict=false,restoreSuppress=false,autoSyncTimer=null;
function syncEnabled(){return localStorage.getItem('mezan_sync_enabled')==='1'}
function refreshSyncLeaseCard(){if(activeTab==='settings')renderSettings()}
function stopSyncLeaseHeartbeat(){if(syncLeaseHeartbeat){clearInterval(syncLeaseHeartbeat);syncLeaseHeartbeat=null}}
function startSyncLeaseHeartbeat(){stopSyncLeaseHeartbeat();if(document.visibilityState!=='visible')return;syncLeaseHeartbeat=setInterval(()=>renewSyncLease(),LEASE_HEARTBEAT_MS)}
function handleLeaseError(error){stopSyncLeaseHeartbeat();syncLeaseStatus=error?.status===401?'expired':'off';refreshSyncLeaseCard()}
async function ensureSyncLease(){const auth=globalThis.MezanAuth;if(!syncEnabled()||!auth?.isSignedIn()||syncLeaseBusy)return;if(!globalThis.MezanLease){syncLeaseStatus='off';return}syncLeaseBusy=true;try{const result=await MezanLease.acquire(auth.getIdToken(),deviceId(),LEASE_API_URL);syncLeaseStatus=result.ok?'active':result.heldByOther?'held':'off';if(result.ok)startSyncLeaseHeartbeat();else stopSyncLeaseHeartbeat()}catch(error){handleLeaseError(error)}finally{syncLeaseBusy=false;refreshSyncLeaseCard()}}
async function renewSyncLease(){const auth=globalThis.MezanAuth;if(!syncEnabled()||!auth?.isSignedIn()||document.visibilityState!=='visible')return;try{const result=await MezanLease.renew(auth.getIdToken(),deviceId(),LEASE_API_URL);syncLeaseStatus=result.ok?'active':result.heldByOther?'held':'off';if(!result.ok)stopSyncLeaseHeartbeat()}catch(error){handleLeaseError(error)}finally{refreshSyncLeaseCard()}}
function releaseSyncLease(){stopSyncLeaseHeartbeat();const token=globalThis.MezanAuth?.getIdToken();if(token&&globalThis.MezanLease)MezanLease.release(token,deviceId(),LEASE_API_URL).catch(()=>{})}
function trySyncLease(){ensureSyncLease()}
function stopDriveSync(){releaseSyncLease();localStorage.removeItem('mezan_sync_enabled');syncLeaseStatus='off';refreshSyncLeaseCard()}
async function signInForSync(){MezanAuth.signOut();try{await MezanAuth.signIn();ensureSyncLease()}catch{syncLeaseStatus='expired';refreshSyncLeaseCard()}}
function syncLeaseStatusLine(){if(syncConflict)return `<p class="hint">${tr('driveConflict')}</p><button class="btn sec" onclick="restoreFromDrive()">${tr('driveGetLatest')}</button>`;if(!syncEnabled())return `<p class="hint">${tr('driveSessionOff')}</p>`;if(syncLeaseStatus==='held')return `<p class="hint">${tr('driveSessionHeld')}</p><button class="btn sec" onclick="trySyncLease()">${tr('driveTryAgain')}</button>`;if(syncLeaseStatus==='paused')return `<p class="hint">${tr('driveSyncPaused')}</p>`;if(syncLeaseStatus==='expired')return `<p class="hint">${tr('driveSessionExpired')}</p><button class="btn sec" onclick="signInForSync()">${tr('driveSignInAgain')}</button>`;if(syncLeaseStatus==='active')return `<p class="hint">${tr('driveSessionActive')}</p>`;return `<p class="hint">${tr('driveSessionOff')}</p>`}
function driveStatus(){const lastSyncedAt=syncMeta().lastSyncedAt;return lastSyncedAt?`${tr('driveLastSynced')}: <bdi dir="ltr">${new Date(lastSyncedAt).toLocaleString()}</bdi>`:tr('driveNotSynced')}
function driveSyncCard(){const auth=globalThis.MezanAuth,signedIn=auth?.isSignedIn();const content=signedIn?`<p class="hint">${driveStatus()}</p>${syncLeaseStatusLine()}<div class="btns"><button class="btn" onclick="saveToDrive()">${tr('driveSave')}</button><button class="btn sec" onclick="restoreFromDrive()">${tr('driveRestore')}</button>${syncEnabled()?`<button class="btn ghost" onclick="stopDriveSync()">${tr('driveStopSync')}</button>`:''}</div>`:`<p class="copy">${tr('driveSyncSignedOut')}</p><div id="settingsGoogleSignIn" class="gsi-container"></div>`;return `<div class="card"><div class="section"><h3>${tr('driveSyncTitle')}</h3></div>${content}</div>`}
function renderSettings(){const cycle=currentCycle(),locked=hasFinancialData();$('settings').innerHTML=`<div class="card"><div class="section"><div><h3>${tr('openCycle')}</h3><p class="copy">${tr('untilNextSalary')}</p></div><span class="cycle-pill"><bdi dir="ltr">${cycle.start}</bdi></span></div></div>${backupDue()?`<div class="card backup-card"><p class="copy">${tr('backupReminder')}</p><button class="btn" onclick="exportData()">${tr('backupNow')}</button></div>`:''}${driveSyncCard()}<div class="reports-stack"><div class="section"><h3>${tr('cycleReports')}</h3><span class="hint">${state.cycleReports.length}</span></div>${state.cycleReports.length?state.cycleReports.map(report=>reportCard(report)).join(''):`<div class="card empty">${tr('noReports')}</div>`}</div><div class="card"><div class="section"><h3>${tr('privacy')}</h3><span class="hint">${tr('local')}</span></div><p class="copy">${tr('privacyText')}</p><div class="field" style="margin-top:12px"><label for="settingsDisplayName">${tr('displayName')}</label><input id="settingsDisplayName" maxlength="60" placeholder="${tr('displayNamePlaceholder')}" value="${escapeHtml(state.settings.displayName||'')}" onchange="saveDisplayName(this.value)"></div><div class="field"><label>${tr('currency')}</label><select ${locked?'disabled aria-disabled="true"':''} onchange="setCurrency(this.value)">${currencies.map(c=>`<option value="${c}" ${state.settings.currency===c?'selected':''}>${currencyOption(c)}</option>`).join('')}</select>${locked?`<span class="hint">${tr('currencyLocked')}</span>`:''}</div><div class="btns"><button class="btn sec" onclick="exportData()">${tr('export')}</button><button class="btn sec" onclick="document.getElementById('importFile').click()">${tr('import')}</button><button class="btn ghost full" onclick="restartWizard()">${tr('editPlan')}</button><button class="btn danger full" onclick="resetAll()">${tr('reset')}</button></div><input id="importFile" type="file" accept="application/json" class="hidden" onchange="importData(event)"></div>`;if(!globalThis.MezanAuth?.isSignedIn())requestAnimationFrame(()=>MezanAuth?.renderButton?.($('settingsGoogleSignIn')))}
async function driveToken(){return MezanAuth.getDriveToken()||MezanAuth.requestDriveToken()}
async function syncWrite(){const auth=globalThis.MezanAuth;if(!syncEnabled()||!auth?.isSignedIn()||!globalThis.MezanDrive||!globalThis.MezanSync||!globalThis.MezanLease)return{status:'error',detail:'sync not ready'};let lease;try{lease=await MezanLease.acquire(auth.getIdToken(),deviceId(),LEASE_API_URL)}catch(e){stopSyncLeaseHeartbeat();if(e?.status===401){syncLeaseStatus='expired';return{status:'expired'}}syncLeaseStatus='off';return{status:'error',detail:`lease: ${e?.message||e}`}}if(!lease||!lease.ok){syncLeaseStatus=lease?.heldByOther?'held':'off';stopSyncLeaseHeartbeat();return{status:lease?.heldByOther?'held':'error',detail:lease?.heldByOther?undefined:'lease not granted'}}syncLeaseStatus='active';startSyncLeaseHeartbeat();const token=auth.getDriveToken();if(!token)return{status:'no_access'};try{const existing=await MezanDrive.findFile(token),base=syncMeta().revisionId||null,remote=existing?.headRevisionId||null,verdict=MezanSync.detectConflict({baseRevisionId:base,hasLocalEdits:true},{revisionId:remote});if(verdict==='conflict'){syncConflict=true;return{status:'conflict'}}const envelope=MezanSync.wrap(state,{deviceId:deviceId(),rev:MezanSync.nextRev(syncMeta().rev||0)}),result=await MezanDrive.saveVault(token,JSON.stringify(envelope));saveSyncMeta({revisionId:result.headRevisionId,rev:envelope.rev,lastSyncedAt:new Date().toISOString()});syncConflict=false;return{status:'ok',revisionId:result.headRevisionId}}catch(e){return{status:'error',detail:`drive: ${e?.message||e}`}}}
function scheduleAutoSync(){if(autoSyncTimer)clearTimeout(autoSyncTimer);autoSyncTimer=setTimeout(()=>{autoSyncTimer=null;autoSyncToDrive().catch(()=>{})},2500)}
async function autoSyncToDrive(){try{const wasConflicted=syncConflict,result=await syncWrite();if(result.status==='conflict'){refreshSyncLeaseCard();if(!wasConflicted)toast(tr('driveConflict'),'error');return}if(result.status==='held'){refreshSyncLeaseCard();return}if(result.status==='expired'){stopSyncLeaseHeartbeat();refreshSyncLeaseCard();return}if(result.status==='no_access'){syncLeaseStatus='paused';refreshSyncLeaseCard();return}if(result.status==='ok')refreshSyncLeaseCard()}catch{}}
async function saveToDrive(){localStorage.setItem('mezan_sync_enabled','1');try{await driveToken()}catch(e){console.error('Mezan Drive access failed:',e);toast(`${tr('driveError')} — access: ${e?.message||e}`,'error');renderSettings();return}let result;try{result=await syncWrite()}catch(e){console.error('Mezan Drive save threw:',e);toast(`${tr('driveError')} — ${e?.message||e}`,'error');renderSettings();return}if(result.status==='ok')toast(tr('driveSaved'),'success');else if(result.status==='held')toast(tr('driveSessionHeld'),'error');else if(result.status==='conflict')toast(tr('driveConflict'),'error');else if(result.status==='expired')toast(tr('driveSessionExpired'),'error');else if(result.status==='no_access')toast(tr('driveSyncPaused'),'error');else{console.error('Mezan Drive save failed:',result.detail);toast(`${tr('driveError')} — ${result.detail||''}`,'error')}renderSettings()}
async function restoreFromDrive(){if(!window.confirm(tr('driveRestoreConfirm')))return;try{const token=await driveToken(),file=await MezanDrive.findFile(token);if(!file){toast(tr('driveNothingSaved'));return}const remote=await MezanDrive.readFile(token,file.id),unwrapped=MezanSync.unwrap(remote.content);state=MezanStorage.normalize(unwrapped.payload);restoreSuppress=true;const saved=save();restoreSuppress=false;if(!saved)return;saveSyncMeta({revisionId:remote.headRevisionId,rev:unwrapped.meta.rev,lastSyncedAt:new Date().toISOString()});syncConflict=false;init();toast(tr('driveRestored'),'success')}catch(e){restoreSuppress=false;console.error('Mezan Drive restore failed:',e);toast(`${tr('driveError')} — ${e?.message||e}`,'error')}}
function exportData(){state.settings.lastBackupAt=localDate();if(!save())return;const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'}));a.download='mezan-backup.json';a.click();URL.revokeObjectURL(a.href);if(activeTab==='settings')renderSettings()}
function arrayCount(value){return Array.isArray(value)?value.length:0}
function importSkippedCount(raw,imported){return ['expenses','recurringPayments','salaryReceipts','cycleReports'].reduce((sum,key)=>sum+Math.max(0,arrayCount(raw[key])-arrayCount(imported[key])),0)}
function importData(ev){const f=ev.target.files[0];if(!f)return;if(f.size>2_000_000){toast(tr('importTooLarge'));ev.target.value='';return}const r=new FileReader();r.onload=()=>{try{const raw=JSON.parse(r.result),imported=MezanStorage.normalize(raw),skipped=importSkippedCount(raw,imported);state=imported;if(save()){init();toast(skipped?tr('importSkipped')(skipped):tr('importOk'),skipped?'error':'success')}}catch{state=JSON.parse(JSON.stringify(persistedState));toast(state.settings.lang==='ar'?'ملف النسخة الاحتياطية غير صالح':'Invalid backup file')}finally{ev.target.value=''}};r.readAsText(f)}
let resetDialogReturnFocus=null;
function resetAll(){
  resetDialogReturnFocus=document.activeElement;
  const overlay=document.createElement('div');
  overlay.className='dialog-overlay';
  overlay.id='resetDialog';
  overlay.innerHTML=`<section class="confirm-dialog" role="dialog" aria-modal="true" aria-labelledby="resetDialogTitle" aria-describedby="resetDialogDesc"><div class="dialog-icon" aria-hidden="true">!</div><h2 id="resetDialogTitle">${tr('resetTitle')}</h2><p id="resetDialogDesc">${tr('resetWarning')}</p><label for="resetConfirmInput">${tr('resetType')}</label><input id="resetConfirmInput" autocomplete="off"><div class="btns"><button class="btn sec" id="cancelReset">${tr('cancel')}</button><button class="btn danger" id="confirmReset" disabled>${tr('resetConfirm')}</button></div></section>`;
  document.body.appendChild(overlay);
  const input=$('resetConfirmInput'),confirmButton=$('confirmReset'),cancelButton=$('cancelReset'),dialog=overlay.querySelector('.confirm-dialog');
  const close=()=>{overlay.remove();resetDialogReturnFocus?.focus()};
  input.addEventListener('input',()=>confirmButton.disabled=input.value.trim()!==tr('resetWord'));
  cancelButton.addEventListener('click',close);
  overlay.addEventListener('click',event=>{if(event.target===overlay)close()});
  confirmButton.addEventListener('click',()=>{const settings={...state.settings};MezanStorage.clear();state=MezanStorage.defaults(settings);persistedState=JSON.parse(JSON.stringify(state));save();close();init()});
  dialog.addEventListener('keydown',event=>{
    if(event.key==='Escape'){event.preventDefault();close();return}
    if(event.key!=='Tab')return;
    const controls=[input,cancelButton,confirmButton].filter(control=>!control.disabled);
    const first=controls[0],last=controls[controls.length-1];
    if(event.shiftKey&&document.activeElement===first){event.preventDefault();last.focus()}
    else if(!event.shiftKey&&document.activeElement===last){event.preventDefault();first.focus()}
  });
  input.focus();
}
function updateConnectionStatus(announce=false){
  const banner=$('connectionBanner');
  if(navigator.onLine){banner.classList.add('hidden');if(announce)toast(tr('onlineAgain'),'success')}
  else{banner.textContent=tr('offlineNow');banner.classList.remove('hidden')}
}
function showTab(id){activeTab=id;renderTab(id);document.querySelectorAll('.panel').forEach(p=>p.classList.add('hidden'));$(id).classList.remove('hidden');document.querySelectorAll('.tab').forEach(b=>{const active=b.dataset.tab===id;b.classList.toggle('active',active);b.setAttribute('aria-current',active?'page':'false')});window.scrollTo({top:0,behavior:'smooth'})}
function runSplash(done){
  const splash=$('splash');
  if(!splash){done();return}
  setTimeout(()=>{
    splash.classList.add('hide');
    setTimeout(()=>{splash.remove();done()},350);
  },1200);
}
if('serviceWorker'in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').catch(()=>{}));
window.addEventListener('online',()=>updateConnectionStatus(true));
window.addEventListener('offline',()=>updateConnectionStatus());
document.addEventListener('visibilitychange',()=>{if(document.visibilityState==='visible')ensureSyncLease();else releaseSyncLease()});
window.addEventListener('pagehide',()=>releaseSyncLease());
updateConnectionStatus();
runSplash(init);
